{"name":"src/index.ts","startLine":1,"endLine":4,"content":"export function compile(source: string) {
  if (source.trim() === "") {
    return "return 0;";
  }

  // Match read<T>() expressions like read<U8>(), read<I32>(), etc.
  const readRegex = /read<(U8|I8|U16|I16|U32|I32|F32|F64)>\(\)/g;
  let jsCode = "";

  // Replace each read<T>() with appropriate parsing code
  let lastIndex = 0;
  let match: RegExpExecArray | null;
  const reads: { type: string }[] = [];

  while ((match = readRegex.exec(source)) !== null) {
    reads.push({ type: match[1] });
  }

  if (reads.length > 0 && source.includes("read<")) {
    // Build code that parses stdin for each read call
    const parts: string[] = [];
    let inputIndex = 0;
    for (const r of reads) {
      switch (r.type) {
        case "U8":
          parts.push(`parseInt(stdIn.split(',')[${inputIndex}] || stdIn, 10)`);
          break;
        case "I8":
          parts.push(`parseInt(stdIn.split(',')[${inputIndex}] || stdIn, 10)`);
          break;
        case "U16":
          parts.push(`parseInt(stdIn.split(',')[${inputIndex}] || stdIn, 10)`);
          break;
        case "I16":
          parts.push(`parseInt(stdIn.split(',')[${inputIndex}] || stdIn, 10)`);
          break;
        case "U32":
          parts.push(`parseInt(stdIn.split(',')[${inputIndex}] || stdIn, 10)`);
          break;
        case "I32":
          parts.push(`parseInt(stdIn.split(',')[${inputIndex}] || stdIn, 10)`);
          break;
        case "F32":
          parts.push(`parseFloat(stdIn.split(',')[${inputIndex}] || stdIn)`);
          break;
        case "F64":
          parts.push(`parseFloat(stdIn.split(',')[${inputIndex}] || stdIn)`);
          break;
      }
      inputIndex++;
    }

    if (reads.length === 1) {
      jsCode = `return ${parts[0]};`;
    } else {
      // Multiple reads - return last one for now as exit code
      jsCode = parts.map((p, i) => `const v${i} = ${p};`).join("\n") + `\nreturn ${parts[parts.length - 1]};`;
    }
  } else {
    // No read calls found, just return 0
    jsCode = "return 0;";
  }

  return jsCode;
}
"}

