{"name":"src/index.ts","startLine":1,"endLine":67,"content":"export function compile(source: string) {
  if (source.trim() === "") {
    return "return 0;";
  }

  const types = ["U8", "I8", "U16", "I16", "U32", "I32", "F32", "F64"];
  const reads: string[] = [];

  for (const type of types) {
    let idx = source.indexOf("read<" + type + ">()");
    while (idx !== -1) {
      reads.push(type);
      idx = source.indexOf("read<" + type + ">()", idx + 1);
    }
  }

  if (reads.length === 0) {
    return "return 0;";
  }

  const parts: string[] = [];
  for (let i = 0; i < reads.length; i++) {
    const type = reads[i];
    let parseExpr = "";
    if (type === "F32" || type === "F64") {
      parseExpr = "parseFloat(stdIn.split(',')[i] || stdIn)";
    } else {
      parseExpr = "parseInt(stdIn.split(',')[i] || stdIn, 10)";
    }
    parts.push(parseExpr);
  }

  if (parts.length === 1) {
    return "return " + parts[0] + ";";
  } else {
    let code = "";
    for (let i = 0; i < parts.length; i++) {
      code += "const v" + i + " = " + parts[i] + ";\n";
    }
    code += "return " + parts[parts.length - 1] + ";";
    return code;
  }
}
"}

